mapper.select:
select spa.id as rowId,spa.name as name,spa.app_date as appDate,spa.digest as digest, spa.note as note,spa.phone as phone,spa.email as email,spa.sub_date as subDate, cspt.name as patentTypeName, fdept.name as deptName, suser.name as subUserName, spaf.name as agencyFeeSourceName, spa.data_status as dataStatus from srm_patent_apply spa left join ct_srm_patent_type cspt on cspt.code=spa.patent_type left join ct_srm_dept fdept on fdept.id=spa.dept_id left join ct_srm_user suser on suser.id=spa.sub_user_id left join ct_srm_patent_agency_fee_source spaf on spaf.code=spa.agency_fee_source where (spa.sub_user_id=#{patentApplyDto.userId} or spa.creator=#{patentApplyDto.userId} or spa.id in (SELECT apply_patent_id FROM srm_patent_apply_author WHERE author_id = #{patentApplyDto.userId}) )
and spa.apply_info_id=#{patentApplyDto.applyInfoId}
and spa.name LIKE CONCAT('%', #{patentApplyDto.name}, '%')
and spa.patent_type =#{patentApplyDto.patentType}
and spa.data_status = #{patentApplyDto.dataStatus}
order by spa.id desc

select spa.id as rowId,spa.name as name,spa.app_date as appDate,spa.digest as digest, spa.note as note,spa.phone as phone,spa.email as email,spa.sub_date as subDate, cspt.name as patentTypeName, fdept.name as deptName, suser.name as subUserName, spaf.name as agencyFeeSourceName, spa.data_status as dataStatus from srm_patent_apply spa left join ct_srm_patent_type cspt on cspt.code=spa.patent_type left join ct_srm_dept fdept on fdept.id=spa.dept_id left join ct_srm_user suser on suser.id=spa.sub_user_id left join ct_srm_patent_agency_fee_source spaf on spaf.code=spa.agency_fee_source left join cf_srm_eaf_rec eafrec on eafrec.sys_no=spa.sys_no and eafrec.check_rec_id=spa.id where eafrec.step_no>1
and ( (spa.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{patentApplyDto.userId}, '|%')) or (eafrec.step_no = (select max(step_no) from cf_srm_eaf_rec seafrec where spa.sys_no=seafrec.sys_no and seafrec.check_rec_id=spa.id) and eafrec.checker_string LIKE CONCAT('%|', #{patentApplyDto.userId}, '|%') and eafrec.check_datetime is not null) or (spa.data_status=0 and eafrec.is_current_step=1 and eafrec.check_result=3 and eafrec.checker_string LIKE CONCAT('%|', #{patentApplyDto.userId}, '|%')) )
and spa.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{patentApplyDto.userId}, '|%')
and spa.data_status=1 and eafrec.check_result="2" and eafrec.checker_string LIKE CONCAT('%|', #{patentApplyDto.userId}, '|%')
and spa.data_status=0 and eafrec.check_result="3" and eafrec.checker_string LIKE CONCAT('%|', #{patentApplyDto.userId}, '|%')
and spa.name LIKE CONCAT('%', #{patentApplyDto.name}, '%')
and spa.patent_type =#{patentApplyDto.patentType}
and spa.sub_date >= #{patentApplyDto.startDate}
and spa.sub_date <= #{patentApplyDto.endDate}
order by eafrec.id desc
